import React from 'react';

function Trade(props) {
    return(
        <div>
            <table>
                <th>
                    <tr>
                        <td>Id</td>
                    </tr>
                </th>
            </table>{props.trade.id}
            {props.trade.stock}
            {props.trade.method}
            {props.trade.quantity}
            {props.trade.profitLoss}
        </div>
    )
}

export default Trade;
